53	// Whether to render 404.html, robotsTXT.txt and similar.
54	// These are usually rendered once in the root of public.
55	func (s siteRenderContext) shouldRenderStandalonePage(kind string) bool {
56		if s.multihost || kind == kinds.KindSitemap {
57			// 1 per site
58			return s.outIdx == 0
59		}
60	
61		if kind == kinds.KindTemporary || kind == kinds.KindStatus404 {
62			// 1 for all output formats
63			return s.outIdx == 0
64		}
65	
66		// 1 for all sites and output formats.
67		return s.languageIdx == 0 && s.outIdx == 0
68	}
