330	// renderDefaultSiteRedirect creates a redirect to the default site's home,
331	// depending on if it lives in sub folder (e.g. /en) or not.
332	// The default site is the site is the combination of defaultContentLanguage,
333	// defaultContentVersion and defaultContentRole.
334	func (s *Site) renderDefaultSiteRedirect(home *pageState) error {
335		if s.conf.DisableDefaultLanguageRedirect || s.conf.DisableDefaultSiteRedirect {
336			return nil
337		}
338	
339		addRedirectInRoot := s.conf.DefaultContentLanguageInSubdir && !s.Conf.IsMultihost()
340		addRedirectInRoot = addRedirectInRoot || s.conf.DefaultContentVersionInSubdir || s.conf.DefaultContentRoleInSubdir
341	
342		homeLink := home.pageOutput.targetPaths().Link // This doesn't have any baseURL paths in it.
343	
344		of := home.outputFormat()
345		homePermalink := home.Permalink()
346	
347		var ps []string
348		if of.Path != "" {
349			if addRedirectInRoot {
350				// For OutputFormats with a path, creating more than one alias will easily create path clashes without much value.
351				ps = []string{paths.AddLeadingAndTrailingSlash(of.Path)}
352			}
353		} else {
354			if addRedirectInRoot {
355				ps = append(ps, "/")
356			}
357	
358			if s.Conf.IsMultilingual() && !s.conf.DefaultContentLanguageInSubdir && !s.Conf.IsMultihost() {
359				// Create redirect from e.g. /en => /
360				ps = append(ps, homeLink+s.Lang()+"/")
361			}
362	
363			// /guest/v1.0.0/en/
364			//    /,/guest/,/guest/v1.0.0  = /guest/v1.0.0/en/
365			// /guest/v1.0.0/
366			//    /,/guest/ =  /guest/v1.0.0/
367			parts := strings.Split(strings.Trim(homeLink, "/"), "/")
368	
369			for i := 0; i < len(parts)-1; i++ {
370				ps = append(ps, paths.AddLeadingAndTrailingSlash(strings.Join(parts[0:i+1], "/")))
371			}
372		}
373	
374		if s.h.Configs.IsMultihost {
375			prefix := "/" + s.LanguagePrefix()
376			for i, p := range ps {
377				ps[i] = path.Join(prefix, p)
378			}
379		}
380	
381		for _, p := range ps {
382			if err := s.publishDestAlias(true, p, homePermalink, of, home); err != nil {
383				return err
384			}
385		}
386	
387		return nil
388	}
