252	func (c *hugoBuilder) initProfiling() (func(), error) {
253		stopCPUProf, err := c.initCPUProfile()
254		if err != nil {
255			return nil, err
256		}
257	
258		stopMutexProf, err := c.initMutexProfile()
259		if err != nil {
260			return nil, err
261		}
262	
263		stopTraceProf, err := c.initTraceProfile()
264		if err != nil {
265			return nil, err
266		}
267	
268		var stopMemTicker func()
269		if c.r.printm {
270			stopMemTicker = c.initMemTicker()
271		}
272	
273		return func() {
274			c.initMemProfile()
275	
276			if stopCPUProf != nil {
277				stopCPUProf()
278			}
279			if stopMutexProf != nil {
280				stopMutexProf()
281			}
282	
283			if stopTraceProf != nil {
284				stopTraceProf()
285			}
286	
287			if stopMemTicker != nil {
288				stopMemTicker()
289			}
290		}, nil
291	}
