559	func (c *hugoBuilder) fullBuild(noBuildLock bool) error {
560		var (
561			g         errgroup.Group
562			langCount map[string]uint64
563		)
564	
565		c.r.logger.Println("Start building sites … ")
566		c.r.logger.Println(hugo.BuildVersionString())
567		c.r.logger.Println()
568		if terminal.IsTerminal(os.Stdout) {
569			defer func() {
570				fmt.Print(showCursor + clearLine)
571			}()
572		}
573	
574		copyStaticFunc := func() error {
575			cnt, err := c.copyStatic()
576			if err != nil {
577				return fmt.Errorf("error copying static files: %w", err)
578			}
579			langCount = cnt
580			return nil
581		}
582		buildSitesFunc := func() error {
583			if err := c.buildSites(noBuildLock); err != nil {
584				return fmt.Errorf("error building site: %w", err)
585			}
586			return nil
587		}
588		// Do not copy static files and build sites in parallel if cleanDestinationDir is enabled.
589		// This flag deletes all static resources in /public folder that are missing in /static,
590		// and it does so at the end of copyStatic() call.
591		var cleanDestinationDir bool
592		c.withConf(func(conf *commonConfig) {
593			cleanDestinationDir = conf.configs.Base.CleanDestinationDir
594		})
595		if cleanDestinationDir {
596			if err := copyStaticFunc(); err != nil {
597				return err
598			}
599			if err := buildSitesFunc(); err != nil {
600				return err
601			}
602		} else {
603			g.Go(copyStaticFunc)
604			g.Go(buildSitesFunc)
605			if err := g.Wait(); err != nil {
606				return err
607			}
608		}
609	
610		h, err := c.hugo()
611		if err != nil {
612			return err
613		}
614		for _, s := range h.Sites {
615			s.ProcessingStats.Static = langCount[s.Language().Lang]
616		}
617	
618		if c.r.gc {
619			count, err := h.GC()
620			if err != nil {
621				return err
622			}
623			for _, s := range h.Sites {
624				// We have no way of knowing what site the garbage belonged to.
625				s.ProcessingStats.Cleaned = uint64(count)
626			}
627		}
628	
629		return nil
630	}
631	
632	func (c *hugoBuilder) fullRebuild(changeType string) {
633		if changeType == configChangeGoMod {
634			// go.mod may be changed during the build itself, and
635			// we really want to prevent superfluous builds.
636			if !c.fullRebuildSem.TryAcquire(1) {
637				return
638			}
639			c.fullRebuildSem.Release(1)
640		}
641	
642		c.fullRebuildSem.Acquire(context.Background(), 1)
643	
644		go func() {
645			defer c.fullRebuildSem.Release(1)
646	
647			c.printChangeDetected(changeType)
648	
649			defer func() {
650				// Allow any file system events to arrive basimplecobra.
651				// This will block any rebuild on config changes for the
652				// duration of the sleep.
653				time.Sleep(2 * time.Second)
654			}()
655	
656			defer c.postBuild("Rebuilt", time.Now())
657	
658			err := c.reloadConfig()
659			if err != nil {
660				// Set the processing on pause until the state is recovered.
661				c.errState.setPaused(true)
662				c.handleBuildErr(err, "Failed to reload config")
663				if c.s.doLiveReload {
664					livereload.ForceRefresh()
665				}
666			} else {
667				c.errState.setPaused(false)
668			}
669	
670			if !c.errState.isPaused() {
671				_, err := c.copyStatic()
672				if err != nil {
673					c.r.logger.Errorln(err)
674					return
675				}
676				err = c.buildSites(false)
677				if err != nil {
678					c.r.logger.Errorln(err)
679				} else if c.s != nil && c.s.doLiveReload {
680					livereload.ForceRefresh()
681				}
682			}
683		}()
684	}
