99	//lint:ignore ST1006 this vs other makes it easier to reason about.
100	func (this TemplateDescriptor) doCompare(category Category, other TemplateDescriptor, sitesMatrixThis, sitesMatrixOther sitesmatrix.VectorProvider) weight {
101		w := weightNoMatch
102	
103		if !this.AlwaysAllowPlainText {
104			// HTML in plain text is OK, but not the other way around.
105			if other.IsPlainText && !this.IsPlainText {
106				return w
107			}
108		}
109	
110		if other.Kind != "" && other.Kind != this.Kind {
111			return w
112		}
113	
114		if other.LayoutFromTemplate != "" && other.LayoutFromTemplate != layoutAll {
115			if this.LayoutFromUser == "" || this.LayoutFromUser != other.LayoutFromTemplate {
116				if other.LayoutFromTemplate != this.LayoutFromTemplate {
117					return w
118				}
119			}
120		}
121	
122		if sitesMatrixOther != nil {
123			// sitesMatrixThis is usually a single Site.
124			// But we also use this method to find all base template variants for a given template,
125			// and in that case we may get multiple vectors (e.g. multiple languages).
126			if sitesMatrixThis == nil || !sitesMatrixOther.HasAnyVector(sitesMatrixThis) {
127				return w
128			}
129		}
130	
131		if other.OutputFormat != "" && other.OutputFormat != this.OutputFormat {
132			if this.MediaType != other.MediaType {
133				return w
134			}
135	
136			// We want e.g. home page in amp output format (media type text/html) to
137			// find a template even if one isn't specified for that output format,
138			// when one exist for the html output format (same media type).
139			skip := category != CategoryBaseof && (this.Kind == "" || (this.Kind != other.Kind && (this.LayoutFromTemplate != other.LayoutFromTemplate && other.LayoutFromTemplate != layoutAll)))
140			if this.LayoutFromUser != "" {
141				skip = skip && (this.LayoutFromUser != other.LayoutFromTemplate)
142			}
143			if skip {
144				return w
145			}
146	
147			// Continue.
148		}
149	
150		if other.MediaType != this.MediaType {
151			return w
152		}
153	
154		// One example of variant1 and 2 is for render codeblocks:
155		// variant1=codeblock, variant2=go (language).
156		if other.Variant1 != "" {
157			if other.Variant1 != this.Variant1 {
158				return w
159			}
160	
161			if other.Variant2 != "" && other.Variant2 != this.Variant2 {
162				return w
163			}
164		}
165	
166		const (
167			weightKind           = 5 // page, home, section, taxonomy, term (and only those)
168			weightcustomLayout   = 6 // custom layout (mylayout, set in e.g. front matter)
169			weightLayoutStandard = 4 // standard layouts (single,list)
170			weightLayoutAll      = 2 // the "all" layout
171			weightOutputFormat   = 4 // a configured output format (e.g. rss, html, json)
172			weightMediaType      = 1 // a configured media type (e.g. text/html, text/plain)
173			weightSitesMatrix    = 1 // a configured language (e.g. en, nn, fr, ...)
174			weightVariant1       = 6 // currently used for render hooks, e.g. "link", "image"
175			weightVariant2       = 4 // currently used for render hooks, e.g. the language "go" in code blocks.
176	
177			// We will use the values for group 2 and 3
178			// if the distance up to the template is shorter than
179			// the one we're comparing with.
180			// E.g for a page in /posts/mypage.md with the
181			// two templates /layouts/posts/single.html and /layouts/page.html,
182			// the first one is the best match even if the second one
183			// has a higher w1 value.
184			weight2Group1 = 1 // kind, standardl layout (single,list,all)
185			weight2Group2 = 2 // custom layout (mylayout)
186	
187			weight3 = 1 // for media type, output format, and dimensions (if not provided).
188		)
189	
190		// Now we now know that the other descriptor is a subset of this.
191		// Now calculate the weights.
192		w.w1++
193	
194		if other.Kind != "" && other.Kind == this.Kind {
195			w.w1 += weightKind
196			w.w2 = weight2Group1
197		}
198	
199		if other.LayoutFromTemplate != "" && (other.LayoutFromTemplate == this.LayoutFromTemplate) {
200			w.w1 += weightLayoutStandard
201			w.w2 = weight2Group1
202		} else if other.LayoutFromTemplate == layoutAll {
203			w.w1 += weightLayoutAll
204			w.w2 = weight2Group1
205		}
206	
207		// LayoutCustom is only set in this (usually from Page.Layout).
208		if this.LayoutFromUser != "" && this.LayoutFromUser == other.LayoutFromTemplate {
209			w.w1 += weightcustomLayout
210			w.w2 = weight2Group2
211		}
212	
213		if sitesMatrixOther != nil {
214			// sitesMatrixThis is usually a single Site.
215			if sitesMatrixThis != nil && sitesMatrixOther.HasAnyVector(sitesMatrixThis) {
216				w.w1 += weightSitesMatrix
217				if wp, ok := sitesMatrixOther.(types.WeightProvider); ok {
218					w.wsm = wp.Weight()
219				} else {
220					w.wsm = weight3
221				}
222			}
223		}
224	
225		if other.OutputFormat != "" && other.OutputFormat == this.OutputFormat {
226			w.w1 += weightOutputFormat
227			w.w3 += weight3
228		}
229	
230		if other.MediaType != "" && other.MediaType == this.MediaType {
231			w.w1 += weightMediaType
232			w.w3 += weight3
233		}
234	
235		if other.Variant1 != "" && other.Variant1 == this.Variant1 {
236			w.w1 += weightVariant1
237		}
238	
239		if other.Variant1 != "" && other.Variant2 == this.Variant2 {
240			w.w1 += weightVariant2
241		}
242	
243		return w
244	}
