281	// process prepares the Sites' sources for a full or partial rebuild.
282	// This will also parse the source and create all the Page objects.
283	func (h *HugoSites) process(ctx context.Context, l logg.LevelLogger, config *BuildCfg, init func(config *BuildCfg) error, events ...fsnotify.Event) error {
284		l = l.WithField("step", "process")
285		defer loggers.TimeTrackf(l, time.Now(), nil, "")
286	
287		if len(events) > 0 {
288			// This is a rebuild triggered from file events.
289			return h.processPartialFileEvents(ctx, l, config, init, events)
290		} else if len(config.WhatChanged.Changes()) > 0 {
291			// Rebuild triggered from remote events.
292			if err := init(config); err != nil {
293				return err
294			}
295			return h.processPartialRebuildChanges(ctx, l, config)
296		}
297		return h.processFull(ctx, l, config)
298	}
