519	func (s *Site) executeDeferredTemplates(de *deps.DeferredExecutions) error {
520		handleFile := func(filename string) error {
521			content, err := afero.ReadFile(s.BaseFs.PublishFs, filename)
522			if err != nil {
523				return err
524			}
525	
526			k := 0
527			changed := false
528	
529			for {
530				if k >= len(content) {
531					break
532				}
533				l := bytes.Index(content[k:], []byte(tpl.HugoDeferredTemplatePrefix))
534				if l == -1 {
535					break
536				}
537				m := bytes.Index(content[k+l:], []byte(tpl.HugoDeferredTemplateSuffix)) + len(tpl.HugoDeferredTemplateSuffix)
538	
539				low, high := k+l, k+l+m
540	
541				forward := l + m
542				id := string(content[low:high])
543	
544				if err := func() error {
545					deferred, found := de.Executions.Get(id)
546					if !found {
547						panic(fmt.Sprintf("deferred execution with id %q not found", id))
548					}
549					deferred.Mu.Lock()
550					defer deferred.Mu.Unlock()
551	
552					if !deferred.Executed {
553						tmpl := s.Deps.GetTemplateStore()
554						ti := s.TemplateStore.LookupByPath(deferred.TemplatePath)
555						if ti == nil {
556							panic(fmt.Sprintf("template %q not found", deferred.TemplatePath))
557						}
558	
559						if err := func() error {
560							buf := bufferpool.GetBuffer()
561							defer bufferpool.PutBuffer(buf)
562	
563							err = tmpl.ExecuteWithContext(deferred.Ctx, ti, buf, deferred.Data)
564							if err != nil {
565								return err
566							}
567							deferred.Result = buf.String()
568							deferred.Executed = true
569	
570							return nil
571						}(); err != nil {
572							return err
573						}
574					}
575	
576					content = append(content[:low], append([]byte(deferred.Result), content[high:]...)...)
577					forward = len(deferred.Result)
578					changed = true
579	
580					return nil
581				}(); err != nil {
582					return err
583				}
584	
585				k += forward
586			}
587	
588			if changed {
589				return afero.WriteFile(s.BaseFs.PublishFs, filename, content, 0o666)
590			}
591	
592			return nil
593		}
594	
595		g := rungroup.Run(context.Background(), rungroup.Config[string]{
596			NumWorkers: s.h.numWorkers,
597			Handle: func(ctx context.Context, filename string) error {
598				return handleFile(filename)
599			},
600		})
601	
602		de.FilenamesWithPostPrefix.ForEeach(func(filename string, _ bool) bool {
603			g.Enqueue(filename)
604			return true
605		})
606	
607		return g.Wait()
608	}
