631	// / printUnusedTemplatesOnce prints unused templates if enabled.
632	func (h *HugoSites) printUnusedTemplatesOnce() error {
633		h.printUnusedTemplatesInit.Do(func() {
634			conf := h.Configs.Base
635			if conf.PrintUnusedTemplates {
636				unusedTemplates := h.GetTemplateStore().UnusedTemplates()
637				for _, unusedTemplate := range unusedTemplates {
638					if unusedTemplate.Fi != nil {
639						h.Log.Warnf("Template %s is unused, source %q", unusedTemplate.PathInfo.Path(), unusedTemplate.Fi.Meta().Filename)
640					} else {
641						h.Log.Warnf("Template %s is unused", unusedTemplate.PathInfo.Path())
642					}
643				}
644			}
645		})
646		return nil
647	}
