261	func (h *HugoSites) initRebuild(config *BuildCfg) error {
262		if !h.Configs.Base.Internal.Watch {
263			return errors.New("rebuild called when not in watch mode")
264		}
265	
266		h.pageTrees.treePagesResources.WalkPrefixRaw("", func(key string, n contentNode) (radix.WalkFlag, contentNode, error) {
267			cnh.resetBuildState(n)
268			return radix.WalkContinue, nil, nil
269		})
270	
271		for _, s := range h.Sites {
272			s.resetBuildState(config.WhatChanged.needsPagesAssembly)
273		}
274	
275		h.reset()
276		h.resetLogs()
277	
278		return nil
279	}
