610	// printPathWarningsOnce prints path warnings if enabled.
611	func (h *HugoSites) printPathWarningsOnce() error {
612		h.printPathWarningsInit.Do(func() {
613			conf := h.Configs.Base
614			if conf.PrintPathWarnings {
615				// We need to do this before any post processing, as that may write to the same files twice
616				// and create false positives.
617				hugofs.WalkFilesystems(h.Fs.PublishDir, func(fs afero.Fs) bool {
618					if dfs, ok := fs.(hugofs.DuplicatesReporter); ok {
619						dupes := dfs.ReportDuplicates()
620						if dupes != "" {
621							h.Log.Warnln("Duplicate target paths:", dupes)
622						}
623					}
624					return false
625				})
626			}
627		})
628		return nil
629	}
