768	func (h *HugoSites) writeBuildStats() error {
769		if h.ResourceSpec == nil {
770			panic("h.ResourceSpec is nil")
771		}
772		if !h.ResourceSpec.BuildConfig().BuildStats.Enabled() {
773			return nil
774		}
775	
776		htmlElements := &publisher.HTMLElements{}
777		for _, s := range h.Sites {
778			stats := s.publisher.PublishStats()
779			htmlElements.Merge(stats.HTMLElements)
780		}
781	
782		filename := filepath.Join(h.Configs.LoadingInfo.BaseConfig.WorkingDir, files.FilenameHugoStatsJSON)
783	
784		existingContent, _ := afero.ReadFile(hugofs.Os, filename)
785	
786		// When rendering only a subset of the site, merge with any existing
787		// hugo_stats.json so that elements from pages not rendered in this build
788		// are preserved (e.g. so Tailwind doesn't strip their classes).
789		// See issue 14939.
790		if len(h.Configs.Base.RenderSegments) > 0 && len(existingContent) > 0 {
791			var existing publisher.PublishStats
792			if err := json.Unmarshal(existingContent, &existing); err == nil {
793				htmlElements.Merge(existing.HTMLElements)
794			} else {
795				h.Log.Warnf("Failed to unmarshal existing hugo_stats.json: %s", err)
796			}
797		}
798	
799		htmlElements.Sort()
800	
801		stats := publisher.PublishStats{
802			HTMLElements: *htmlElements,
803		}
804	
805		var buf bytes.Buffer
806		enc := json.NewEncoder(&buf)
807		enc.SetEscapeHTML(false)
808		enc.SetIndent("", "  ")
809		err := enc.Encode(stats)
810		if err != nil {
811			return err
812		}
813		js := buf.Bytes()
814	
815		if bytes.Equal(existingContent, js) {
816			return nil
817		}
818	
819		// Make sure it's always written to the OS fs.
820		if err := afero.WriteFile(hugofs.Os, filename, js, 0o666); err != nil {
821			return err
822		}
823	
824		// Write to the destination as well if it's a in-memory fs.
825		if !hugofs.IsOsFs(h.Fs.Source) {
826			if err := afero.WriteFile(h.Fs.WorkingDirWritable, filename, js, 0o666); err != nil {
827				return err
828			}
829		}
830	
831		// This step may be followed by a post process step that may
832		// rebuild e.g. CSS, so clear any cache that's defined for the hugo_stats.json.
833		h.dynacacheGCFilenameIfNotWatchedAndDrainMatching(filename)
834	
835		return nil
836	}
