838	type pathChange struct {
839		// The path to the changed file.
840		p *paths.Path
841	
842		// If true, this is a structural change (e.g. a delete or a rename).
843		structural bool
844	
845		// If true, this is a directory.
846		isDir bool
847	}
848	
849	func (p pathChange) isStructuralChange() bool {
850		return p.structural || p.isDir
851	}
