853	func (h *HugoSites) processPartialRebuildChanges(ctx context.Context, l logg.LevelLogger, config *BuildCfg) error {
854		if err := h.resolveAndClearStateForIdentities(ctx, l, nil, config.WhatChanged.Drain()); err != nil {
855			return err
856		}
857	
858		if err := h.processContentAdaptersOnRebuild(ctx, config); err != nil {
859			return err
860		}
861		return nil
